Javascript.validate:
			//Validation: only numeric characters allowed and two decimal places.
			//Error message: Currency amounts must be in the format of 0.00
			//Currency field. Max value. 99999999.99	
              var value = Services.getValue(TotalAmount.dataBinding);      
                  var maxVal = 99999999.99;         
                  var err = null;
                  
                  if( '0.00 ' != value )
                  {   err = validateCurrencyValue(value, maxVal);
                      if( null == err)
                      { 
                        var returnVal = WPU.formatToTwoDP(value);
                        Services.setValue(TotalAmount.dataBinding, returnVal);
                      } 
                  }
                  return err;

Javascript.transformToModel:

     if( null == value || "" == value )
     {  return "0.00 ";
     }
     else
     { return value;
     }

Javascript.miscCode:
function DefaultCurrency9112() {}
DefaultCurrency9112.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9112.tabIndex = -1;
DefaultCurrency9112.maxLength = 1;
DefaultCurrency9112.isReadOnly = function(){return true;}
DefaultCurrency9112.isTemporary = function(){return true;}
DefaultCurrency9112.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9112.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
